"use client";
import React, { Suspense, useRef } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import { Preload } from "@react-three/drei";
import * as THREE from "three";

import { useScrollStore, useThemeStore } from "@/stores";
import StarsContainer from "../models/Stars";
import CloudContainer from "../models/Cloud";
import { Wanderer } from "../models/Wanderer";
import { Memory } from "../models/Memory";
import WindowModel from "../models/WindowModel";

// Sub-component to drive real-time camera movements and model animations
const BackgroundSceneContent = () => {
  const scrollProgress = useScrollStore((state) => state.scrollProgress);
  const isDarkTheme = useThemeStore((state) => state.theme.type === "dark");

  const windowRef = useRef<THREE.Group>(null);
  const memoryRef = useRef<THREE.Group>(null);
  const wandererRef = useRef<THREE.Group>(null);

  useFrame((state, delta) => {
    // 1. Interactive 3D cursor panning parallax (dampen camera shift on mouse pointer movement)
    const targetX = state.pointer.x * 2.5;
    const targetY = state.pointer.y * 1.5;
    state.camera.position.x = THREE.MathUtils.damp(state.camera.position.x, targetX, 2.5, delta);
    state.camera.position.y = THREE.MathUtils.damp(state.camera.position.y, targetY + 2, 2.5, delta);

    // 2. Immersive scroll depth progression (plunge camera on scroll)
    const targetZ = 6 + scrollProgress * 18;
    state.camera.position.z = THREE.MathUtils.damp(state.camera.position.z, targetZ, 2.5, delta);

    // 3. Subtle floating rotation and wave animations for 3D elements
    const elapsed = state.clock.getElapsedTime();

    if (windowRef.current) {
      windowRef.current.rotation.y = elapsed * 0.04;
      windowRef.current.position.y = -26.5 + Math.sin(elapsed * 0.4) * 0.15;
    }

    if (memoryRef.current) {
      memoryRef.current.rotation.y = -elapsed * 0.06;
      memoryRef.current.position.y = -4 + Math.cos(elapsed * 0.3) * 0.2;
    }

    if (wandererRef.current) {
      wandererRef.current.rotation.y = elapsed * 0.05;
      wandererRef.current.position.y = -10 + Math.sin(elapsed * 0.35) * 0.15;
    }
  });

  return (
    <>
      <ambientLight intensity={isDarkTheme ? 0.35 : 0.75} />
      <pointLight position={[10, 10, 10]} intensity={1.5} />
      <directionalLight position={[-5, 8, -5]} intensity={1.2} />

      {/* 3D Stars background (active only in dark theme) */}
      <StarsContainer />

      {/* Dynamic 3D clouds wrapper */}
      <CloudContainer />

      {/* 3D Window Model (placed close for Hero section) */}
      <group ref={windowRef} position={[0, -26.5, 5.69]} scale={0.75}>
        <pointLight castShadow position={[1, 1, -2.5]} intensity={60} distance={10} />
        <WindowModel />
      </group>

      {/* 3D Dali Clocks (Memory) (visible as camera plunges down) */}
      <group ref={memoryRef} position={[-3.5, -4, -6]} scale={1.2} rotation={[0.2, 0.4, 0.1]}>
        <Memory />
      </group>

      {/* 3D Wanderer Model (visible in deeper sections) */}
      <group ref={wandererRef} position={[3.8, -10, -8]} scale={0.05} rotation={[0.1, -0.4, 0]}>
        <Wanderer />
      </group>
    </>
  );
};

// React.memo protects the canvas from re-rendering during state updates elsewhere in the DOM
const ThreeBackground = React.memo(() => {
  return (
    <div id="canvas-container">
      <Canvas
        camera={{ position: [0, 2, 6], fov: 75 }}
        gl={{ antialias: true, alpha: true }}
        dpr={[1, 2]}
      >
        <Suspense fallback={null}>
          <BackgroundSceneContent />
          <Preload all />
        </Suspense>
      </Canvas>
    </div>
  );
});

ThreeBackground.displayName = "ThreeBackground";
export default ThreeBackground;
